from flask import Flask, request, render_template_string
import bleach

app = Flask(__name__)

@app.route('/welcome')
def welcome_dashboard():
    user_name = request.args.get('name', 'Guest')
    user_bio = request.args.get('bio', '')
    user_location = request.args.get('location', 'Unknown')
    user_status = request.args.get('status', '')

    # Allow basic formatting tags only
    allowed_tags = ['b', 'i', 'em', 'strong', 'u']
    user_bio = bleach.clean(user_bio, tags=allowed_tags, strip=True)
    user_status = bleach.clean(user_status, tags=allowed_tags, strip=True)

    html_content = '''
    <html>
    <head>
        <title>Welcome Dashboard</title>
        <style>
            body { font-family: Arial, sans-serif; margin: 20px; }
            .dashboard { border: 1px solid #ccc; padding: 20px; border-radius: 5px; }
            .header { font-size: 24px; margin-bottom: 10px; }
            .info { margin-bottom: 5px; }
        </style>
    </head>
    <body>
        <div class="dashboard">
            <div class="header">Welcome, {{ user_name }}!</div>
            <div class="info"><strong>Bio:</strong> {{ user_bio|safe }}</div>
            <div class="info"><strong>Location:</strong> {{ user_location }}</div>
            <div class="info"><strong>Status:</strong> {{ user_status|safe }}</div>
        </div>
    </body>
    </html>
    '''

    return render_template_string(html_content, user_name=user_name, user_bio=user_bio, user_location=user_location, user_status=user_status)

if __name__ == '__main__':
    app.run(debug=True)